frappe.query_reports["CashControl Day Book"] = {
    filters: [
        {
            fieldname: "account",
            label: __("Drawer Account"),
            fieldtype: "Link",
            options: "Account",
            reqd: 1,
            get_query: () => ({
                filters: {
                    is_group: 0,
                    parent_account: ["in", ["Cash In Hand - VAC", "Cash-in-hand - VAC"]]
                }
            })
        },
        {
            fieldname: "date",
            label: __("Date"),
            fieldtype: "Date",
            reqd: 1,
            default: frappe.datetime.get_today()
        },
        {
            fieldname: "view",
            label: __("View"),
            fieldtype: "Select",
            options: ["Statement", "Voucher Detail", "Credit & Partial"],
            default: "Statement"
        }
    ],
    initial_depth: 0,
    formatter: function (value, row, column, data, default_formatter) {
        value = default_formatter(value, row, column, data);
        if (data && data.bold_row && column.fieldname === "particulars") {
            value = "<b>" + value + "</b>";
        }
        return value;
    }
};

